"use client";

import Link from "next/link";
import { useCallback, useEffect, useState } from "react";
import { Badge } from "@/components/ui/badge";
import { Button } from "@/components/ui/button";
import { Table, TableBody, TableCell, TableHead, TableHeader, TableRow } from "@/components/ui/table";
import { apiFetch } from "@/lib/api";
import type { BgvAccessLog } from "@/lib/types";

type ApiMeta = {
  total: number;
  page: number;
  limit: number;
  pages: number;
};

export default function BgvAccessPage() {
  const [records, setRecords] = useState<BgvAccessLog[]>([]);
  const [meta, setMeta] = useState<ApiMeta>({ total: 0, page: 1, limit: 20, pages: 1 });
  const [page, setPage] = useState(1);
  const [loading, setLoading] = useState(true);
  const [message, setMessage] = useState("");

  const load = useCallback(async () => {
    setLoading(true);
    setMessage("");

    try {
      const response = await apiFetch<{ data: BgvAccessLog[]; meta: ApiMeta }>(
        `/api/bgv/access-logs?page=${page}&limit=20`
      );
      setRecords(response.data);
      setMeta(response.meta);
    } catch (err) {
      setMessage(err instanceof Error ? err.message : "Unable to load BGV access records");
    } finally {
      setLoading(false);
    }
  }, [page]);

  useEffect(() => {
    load();
  }, [load]);

  return (
    <div className="space-y-6">
      <div>
        <p className="text-sm uppercase text-muted-foreground">Audit tracking</p>
        <h1 className="text-3xl font-semibold">BGV Access Records</h1>
        <p className="mt-2 text-sm text-muted-foreground">
          Public verification form submissions are saved in activity logs and listed here for HR audit review.
        </p>
      </div>

      <section className="rounded-lg border border-border bg-background shadow-soft">
        <div className="flex flex-col gap-3 border-b border-border p-5 md:flex-row md:items-center md:justify-between">
          <div>
            <h2 className="text-base font-semibold">Verification Access Log</h2>
            <p className="text-sm text-muted-foreground">
              Showing page {meta.page} of {Math.max(meta.pages, 1)} with {meta.total} saved access records.
            </p>
          </div>
          <div className="flex gap-2">
            <Button type="button" variant="outline" disabled={loading || page <= 1} onClick={() => setPage((current) => Math.max(1, current - 1))}>
              Previous
            </Button>
            <Button type="button" variant="outline" disabled={loading || page >= meta.pages} onClick={() => setPage((current) => current + 1)}>
              Next
            </Button>
          </div>
        </div>
        {message ? <p className="border-b border-border p-5 text-sm text-red-600">{message}</p> : null}
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Accessed At</TableHead>
              <TableHead>Record</TableHead>
              <TableHead>Verifier</TableHead>
              <TableHead>Organization</TableHead>
              <TableHead>Purpose</TableHead>
              <TableHead>Result</TableHead>
              <TableHead>Request</TableHead>
            </TableRow>
          </TableHeader>
          <TableBody>
            {loading ? (
              <TableRow>
                <TableCell colSpan={7} className="text-center text-muted-foreground">
                  Loading BGV access records...
                </TableCell>
              </TableRow>
            ) : records.length === 0 ? (
              <TableRow>
                <TableCell colSpan={7} className="text-center text-muted-foreground">
                  No public BGV access records saved yet.
                </TableCell>
              </TableRow>
            ) : (
              records.map((record) => (
                <TableRow key={record.id}>
                  <TableCell className="whitespace-nowrap text-sm">{new Date(record.created_at).toLocaleString()}</TableCell>
                  <TableCell>
                    {record.intern ? (
                      <Link className="text-sm font-medium underline-offset-4 hover:underline" href={`/interns/${record.intern.id}`}>
                        {record.intern.name}
                      </Link>
                    ) : (
                      <div className="text-sm font-medium">Unknown record</div>
                    )}
                    <div className="font-mono text-xs text-muted-foreground">{record.reference_id}</div>
                  </TableCell>
                  <TableCell>
                    <div className="text-sm font-medium">{record.verifier.name}</div>
                    <div className="text-xs text-muted-foreground">{record.verifier.email}</div>
                    {record.verifier.phone ? <div className="text-xs text-muted-foreground">{record.verifier.phone}</div> : null}
                  </TableCell>
                  <TableCell>
                    <div className="text-sm">{record.verifier.organization}</div>
                    {record.verifier.designation ? <div className="text-xs text-muted-foreground">{record.verifier.designation}</div> : null}
                  </TableCell>
                  <TableCell>
                    <div className="text-sm">{record.verifier.purpose}</div>
                    <div className="text-xs text-muted-foreground">{record.access_type}</div>
                    {record.verifier.notes ? <div className="mt-1 max-w-[220px] text-xs text-muted-foreground">{record.verifier.notes}</div> : null}
                  </TableCell>
                  <TableCell>
                    <Badge variant={record.result_status === "Valid" ? "teal" : "red"}>{record.result_status}</Badge>
                  </TableCell>
                  <TableCell>
                    <div className="text-xs text-muted-foreground">IP: {record.request.ip_address}</div>
                    <div className="max-w-[240px] truncate text-xs text-muted-foreground" title={record.request.user_agent}>
                      {record.request.user_agent}
                    </div>
                  </TableCell>
                </TableRow>
              ))
            )}
          </TableBody>
        </Table>
      </section>
    </div>
  );
}
